428: /*
429:  * Extract a CopyOnErrorChoice value from a DefElem.
430:  */
431: static CopyOnErrorChoice
432: defGetCopyOnErrorChoice(DefElem *def, ParseState *pstate, bool is_from)
433: {
434: 	char	   *sval = defGetString(def);
435: 
436: 	if (!is_from)
437: 		ereport(ERROR,
438: 				(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
439: 		/*- translator: first %s is the name of a COPY option, e.g. ON_ERROR,
440: 		 second %s is a COPY with direction, e.g. COPY TO */
441: 				 errmsg("COPY %s cannot be used with %s", "ON_ERROR", "COPY TO"),
442: 				 parser_errposition(pstate, def->location)));
443: 
444: 	/*
445: 	 * Allow "stop", or "ignore" values.
446: 	 */
447: 	if (pg_strcasecmp(sval, "stop") == 0)
448: 		return COPY_ON_ERROR_STOP;
449: 	if (pg_strcasecmp(sval, "ignore") == 0)
450: 		return COPY_ON_ERROR_IGNORE;
451: 
452: 	ereport(ERROR,
453: 			(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
454: 	/*- translator: first %s is the name of a COPY option, e.g. ON_ERROR */
455: 			 errmsg("COPY %s \"%s\" not recognized", "ON_ERROR", sval),
456: 			 parser_errposition(pstate, def->location)));
457: 	return COPY_ON_ERROR_STOP;	/* keep compiler quiet */
458: }
