460: /*
461:  * Extract REJECT_LIMIT value from a DefElem.
462:  *
463:  * REJECT_LIMIT can be specified in two ways: as an int64 for the COPY command
464:  * option or as a single-quoted string for the foreign table option using
465:  * file_fdw. Therefore this function needs to handle both formats.
466:  */
467: static int64
468: defGetCopyRejectLimitOption(DefElem *def)
469: {
470: 	int64		reject_limit;
471: 
472: 	if (def->arg == NULL)
473: 		ereport(ERROR,
474: 				(errcode(ERRCODE_SYNTAX_ERROR),
475: 				 errmsg("%s requires a numeric value",
476: 						def->defname)));
477: 	else if (nodeTag(def->arg) == T_String)
478: 		reject_limit = pg_strtoint64(strVal(def->arg));
479: 	else
480: 		reject_limit = defGetInt64(def);
481: 
482: 	if (reject_limit <= 0)
483: 		ereport(ERROR,
484: 				(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
485: 				 errmsg("REJECT_LIMIT (%" PRId64 ") must be greater than zero",
486: 						reject_limit)));
487: 
488: 	return reject_limit;
489: }
