491: /*
492:  * Extract a CopyLogVerbosityChoice value from a DefElem.
493:  */
494: static CopyLogVerbosityChoice
495: defGetCopyLogVerbosityChoice(DefElem *def, ParseState *pstate)
496: {
497: 	char	   *sval;
498: 
499: 	/*
500: 	 * Allow "silent", "default", or "verbose" values.
501: 	 */
502: 	sval = defGetString(def);
503: 	if (pg_strcasecmp(sval, "silent") == 0)
504: 		return COPY_LOG_VERBOSITY_SILENT;
505: 	if (pg_strcasecmp(sval, "default") == 0)
506: 		return COPY_LOG_VERBOSITY_DEFAULT;
507: 	if (pg_strcasecmp(sval, "verbose") == 0)
508: 		return COPY_LOG_VERBOSITY_VERBOSE;
509: 
510: 	ereport(ERROR,
511: 			(errcode(ERRCODE_INVALID_PARAMETER_VALUE),
512: 	/*- translator: first %s is the name of a COPY option, e.g. ON_ERROR */
513: 			 errmsg("COPY %s \"%s\" not recognized", "LOG_VERBOSITY", sval),
514: 			 parser_errposition(pstate, def->location)));
515: 	return COPY_LOG_VERBOSITY_DEFAULT;	/* keep compiler quiet */
516: }
