518: /*
519:  * Process the statement option list for COPY.
520:  *
521:  * Scan the options list (a list of DefElem) and transpose the information
522:  * into *opts_out, applying appropriate error checking.
523:  *
524:  * If 'opts_out' is not NULL, it is assumed to be filled with zeroes initially.
525:  *
526:  * This is exported so that external users of the COPY API can sanity-check
527:  * a list of options.  In that usage, 'opts_out' can be passed as NULL and
528:  * the collected data is just leaked until CurrentMemoryContext is reset.
529:  *
530:  * Note that additional checking, such as whether column names listed in FORCE
531:  * QUOTE actually exist, has to be applied later.  This just checks for
532:  * self-consistency of the options list.
533:  */
534: void
535: ProcessCopyOptions(ParseState *pstate,
536: 				   CopyFormatOptions *opts_out,
537: 				   bool is_from,
538: 				   List *options)
539: {
540: 	bool		format_specified = false;
541: 	bool		freeze_specified = false;
542: 	bool		header_specified = false;
543: 	bool		on_error_specified = false;
544: 	bool		log_verbosity_specified = false;
545: 	bool		reject_limit_specified = false;
546: 	ListCell   *option;
547: 
548: 	/* Support external use for option sanity checking */
549: 	if (opts_out == NULL)
550: 		opts_out = (CopyFormatOptions *) palloc0(sizeof(CopyFormatOptions));
551: 
552: 	opts_out->file_encoding = -1;
553: 
554: 	/* Extract options from the statement node tree */
555: 	foreach(option, options)
556: 	{
557: 		DefElem    *defel = lfirst_node(DefElem, option);
558: 
559: 		if (strcmp(defel->defname, "format") == 0)
560: 		{
561: 			char	   *fmt = defGetString(defel);
562: 
563: 			if (format_specified)
564: 				errorConflictingDefElem(defel, pstate);
565: 			format_specified = true;
