969: /*
970:  * CopyGetAttnums - build an integer list of attnums to be copied
971:  *
972:  * The input attnamelist is either the user-specified column list,
973:  * or NIL if there was none (in which case we want all the non-dropped
974:  * columns).
975:  *
976:  * We don't include generated columns in the generated full list and we don't
977:  * allow them to be specified explicitly.  They don't make sense for COPY
978:  * FROM, but we could possibly allow them for COPY TO.  But this way it's at
979:  * least ensured that whatever we copy out can be copied back in.
980:  *
981:  * rel can be NULL ... it's only used for error reports.
982:  */
983: List *
984: CopyGetAttnums(TupleDesc tupDesc, Relation rel, List *attnamelist)
985: {
986: 	List	   *attnums = NIL;
987: 
988: 	if (attnamelist == NIL)
989: 	{
990: 		/* Generate default column list */
991: 		int			attr_count = tupDesc->natts;
992: 		int			i;
993: 
994: 		for (i = 0; i < attr_count; i++)
995: 		{
996: 			CompactAttribute *attr = TupleDescCompactAttr(tupDesc, i);
997: 
998: 			if (attr->attisdropped || attr->attgenerated)
999: 				continue;
1000: 			attnums = lappend_int(attnums, i + 1);
1001: 		}
1002: 	}
1003: 	else
1004: 	{
1005: 		/* Validate the user-supplied list and extract attnums */
1006: 		ListCell   *l;
1007: 
1008: 		foreach(l, attnamelist)
1009: 		{
1010: 			char	   *name = strVal(lfirst(l));
1011: 			int			attnum;
1012: 			int			i;
1013: 
1014: 			/* Lookup column name */
1015: 			attnum = InvalidAttrNumber;
1016: 			for (i = 0; i < tupDesc->natts; i++)
1017: 			{
1018: 				Form_pg_attribute att = TupleDescAttr(tupDesc, i);
1019: 
1020: 				if (att->attisdropped)
1021: 					continue;
1022: 				if (namestrcmp(&(att->attname), name) == 0)
1023: 				{
1024: 					if (att->attgenerated)
1025: 						ereport(ERROR,
1026: 								(errcode(ERRCODE_INVALID_COLUMN_REFERENCE),
1027: 								 errmsg("column \"%s\" is a generated column",
1028: 										name),
1029: 								 errdetail("Generated columns cannot be used in COPY.")));
1030: 					attnum = att->attnum;
1031: 					break;
1032: 				}
1033: 			}
1034: 			if (attnum == InvalidAttrNumber)
1035: 			{
1036: 				if (rel != NULL)
1037: 					ereport(ERROR,
1038: 							(errcode(ERRCODE_UNDEFINED_COLUMN),
1039: 							 errmsg("column \"%s\" of relation \"%s\" does not exist",
1040: 									name, RelationGetRelationName(rel))));
1041: 				else
1042: 					ereport(ERROR,
1043: 							(errcode(ERRCODE_UNDEFINED_COLUMN),
