155: static const CopyFromRoutine *
156: CopyFromGetRoutine(const CopyFormatOptions *opts)
157: {
158: 	if (opts->csv_mode)
159: 		return &CopyFromRoutineCSV;
160: 	else if (opts->binary)
161: 		return &CopyFromRoutineBinary;
162: 
163: 	/* default is text */
